solutions.javascript:
// Define a generic function to calculate the result of an operation.
function calculate<T>(a: T, b: T, op: string): T | string {
    switch (op) {
        case '+': return a + b;
        case '-': return a - b;
        case '*': return a * b;
        case '/':
            if (b === 0) return 'Error';
            return a / b;
        default: throw new Error('Invalid operator');
    }
}
